// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * EPIC 3: Immutable Vote Ledger (header anchoring)
 * - Permissioned writers
 * - Append-only blocks
 * - Hash-linked blocks (prevHash)
 * - Optional write-quorum (propose/approve/finalize)
 */
contract VoteLedger {
    address public admin;
    uint256 public quorum; // approvals required to finalize

    struct BlockHeader {
        uint256 height;
        bytes32 prevHash;
        bytes32 merkleRoot;
        bytes32 blockHash;
        uint256 timestamp;
    }

    // Finalized chain
    mapping(uint256 => BlockHeader) public blocks;
    uint256 public tipHeight;
    bytes32 public tipHash; // last finalized blockHash

    // Permissioned writers
    mapping(address => bool) public isWriter;

    // Proposals (for quorum simulation)
    struct Proposal {
        BlockHeader header;
        uint256 approvals;
        bool exists;
        bool finalized;
    }
    mapping(bytes32 => Proposal) public proposals;
    mapping(bytes32 => mapping(address => bool)) public hasApproved;

    event WriterUpdated(address indexed writer, bool allowed);
    event QuorumUpdated(uint256 quorum);

    event BlockProposed(bytes32 indexed headerHash, uint256 height, bytes32 prevHash, bytes32 merkleRoot, bytes32 blockHash);
    event BlockApproved(bytes32 indexed headerHash, address indexed writer, uint256 approvals);
    event BlockFinalized(uint256 height, bytes32 blockHash, bytes32 merkleRoot);

    modifier onlyAdmin() {
        require(msg.sender == admin, "not admin");
        _;
    }

    modifier onlyWriter() {
        require(isWriter[msg.sender], "not writer");
        _;
    }

    constructor(uint256 _quorum) {
        admin = msg.sender;
        quorum = _quorum;
        isWriter[msg.sender] = true; // deployer is writer by default
        emit WriterUpdated(msg.sender, true);
        emit QuorumUpdated(_quorum);
    }

    function setWriter(address writer, bool allowed) external onlyAdmin {
        isWriter[writer] = allowed;
        emit WriterUpdated(writer, allowed);
    }

    function setQuorum(uint256 _quorum) external onlyAdmin {
        require(_quorum >= 1, "quorum must be >=1");
        quorum = _quorum;
        emit QuorumUpdated(_quorum);
    }

    function computeHeaderHash(BlockHeader memory h) public pure returns (bytes32) {
        // Canonical hash (must match backend)
        return keccak256(abi.encode(h.height, h.prevHash, h.merkleRoot, h.blockHash, h.timestamp));
    }

    function proposeBlock(
        uint256 height,
        bytes32 prevHash,
        bytes32 merkleRoot,
        bytes32 blockHash,
        uint256 timestamp
    ) external onlyWriter returns (bytes32 headerHash) {
        require(height == tipHeight + 1, "bad height");
        require(prevHash == tipHash, "prev mismatch");

        BlockHeader memory h = BlockHeader(height, prevHash, merkleRoot, blockHash, timestamp);
        headerHash = computeHeaderHash(h);

        Proposal storage p = proposals[headerHash];
        require(!p.exists, "proposal exists");

        proposals[headerHash] = Proposal({
            header: h,
            approvals: 0,
            exists: true,
            finalized: false
        });

        emit BlockProposed(headerHash, height, prevHash, merkleRoot, blockHash);

        // auto-approve proposer
        _approve(headerHash, msg.sender);
    }

    function approveBlock(bytes32 headerHash) external onlyWriter {
        _approve(headerHash, msg.sender);
    }

    function _approve(bytes32 headerHash, address writer) internal {
        Proposal storage p = proposals[headerHash];
        require(p.exists, "unknown proposal");
        require(!p.finalized, "already finalized");
        require(!hasApproved[headerHash][writer], "already approved");

        hasApproved[headerHash][writer] = true;
        p.approvals += 1;

        emit BlockApproved(headerHash, writer, p.approvals);
    }

    function finalizeBlock(bytes32 headerHash) external onlyWriter {
        Proposal storage p = proposals[headerHash];
        require(p.exists, "unknown proposal");
        require(!p.finalized, "already finalized");
        require(p.approvals >= quorum, "not enough approvals");

        // Safety re-check
        require(p.header.height == tipHeight + 1, "height changed");
        require(p.header.prevHash == tipHash, "prev changed");

        blocks[p.header.height] = p.header;
        tipHeight = p.header.height;
        tipHash = p.header.blockHash;
        p.finalized = true;

        emit BlockFinalized(p.header.height, p.header.blockHash, p.header.merkleRoot);
    }

    function getBlock(uint256 height) external view returns (BlockHeader memory) {
        return blocks[height];
    }
}

